    "safety.kicker": "Trust & safety",
    "safety.title": "Safer boat sitting starts with preparation",
    "safety.intro": "Use these practical checks before, during and after every boat sit.",
    "safety.verification.title": "Identity and verification",
    "safety.verification.text":
      "Complete available identity checks and confirm that names and contact details match before agreeing to a sit.",
    "safety.profiles.title": "Review profiles and history",
    "safety.profiles.text":
      "Read references, reviews and experience carefully. Ask follow-up questions about gaps or unfamiliar systems.",
    "safety.video.title": "Meet by video",
    "safety.video.text":
      "Arrange a video call, involve everyone who will stay aboard and walk through the vessel live when practical.",
    "safety.expectations.title": "Put expectations in writing",
    "safety.expectations.text":
      "Record dates, responsibilities, access, expenses, updates, visitors and cancellation plans in writing.",
    "safety.handover.title": "Complete a boat-specific handover",
    "safety.handover.text":
      "Cover systems, seacocks, bilges, batteries, shore power, engines, weather actions, emergency contacts and shutdown procedures.",
    "safety.insurance.title": "Check insurance",
    "safety.insurance.text":
      "Owners and sitters should independently confirm applicable vessel, marina, travel, liability and personal insurance.",
    "safety.pets.title": "Plan for pets",
    "safety.pets.text":
      "Document feeding, medication, exercise, vet contacts, transport and safe movement around decks and docks.",
    "safety.marina.title": "Follow marina rules",
    "safety.marina.text":
      "Confirm guest registration, access, parking, waste, noise, security and emergency procedures with the marina.",
    "safety.redFlags.title": "Recognize red flags",
    "safety.redFlags.text":
      "Pause if someone pressures you, avoids video, requests unusual payments, withholds documentation, changes key facts, or tries to move the conversation off platform right away.",
    "safety.reporting.title": "Report incidents",
    "safety.reporting.text":
      "Preserve messages, photos, dates and receipts. Report safety concerns to Boatstead support and relevant insurers or authorities.",
    "safety.emergency.title": "In an emergency",
    "safety.emergency.text":
      "Protect life first. Contact local emergency or maritime rescue services, then the owner, marina and insurer as appropriate.",
    "safety.disclaimerTitle": "Important limitation",
    "safety.disclaimerText":
      "Boatstead does not replace emergency services, insurers, qualified marine professionals or professional maritime advice.",
