    "skill.tenderHandling": "Obrada tendera",
    "safety.kicker": "Povjerenje i sigurnost",
    "safety.title": "Sigurnije sjedenje u brodu počinje pripremom",
    "safety.intro":
      "Koristite ove praktične provjere prije, tijekom i nakon svakog sjedenja na brodu.",
    "safety.verification.title": "Identitet i provjera",
    "safety.verification.text":
      "Dovršite dostupne provjere identiteta i potvrdite da se imena i podaci za kontakt podudaraju prije nego što pristanete na sjedište.",
    "safety.profiles.title": "Pregledajte profile i povijest",
    "safety.profiles.text":
      "Pažljivo pročitajte reference, recenzije i iskustvo. Postavite dodatna pitanja o prazninama ili nepoznatim sustavima.",
    "safety.video.title": "Upoznajte se putem videa",
    "safety.video.text":
      "Dogovorite video poziv, uključite sve koji će ostati na brodu i prošećite plovilom uživo kada je to praktično.",
    "safety.expectations.title": "Napiši očekivanja",
    "safety.expectations.text":
      "Zabilježite datume, odgovornosti, pristup, troškove, ažuriranja, posjetitelje i planove otkazivanja u pisanom obliku.",
    "safety.handover.title": "Dovršite primopredaju specifičnu za brod",
    "safety.handover.text":
      "Poklopni sustavi, morske slavine, kaljuže, baterije, napajanje s obale, motori, vremenski uvjeti, kontakti za hitne slučajeve i postupci gašenja.",
    "safety.insurance.title": "Provjerite osiguranje",
    "safety.insurance.text":
      "Vlasnici i čuvari trebaju neovisno potvrditi primjenjivo osiguranje plovila, marine, putovanja, odgovornosti i osobno osiguranje.",
    "safety.pets.title": "Plan za kućne ljubimce",
    "safety.pets.text":
      "Hranjenje dokumenata, lijekovi, vježbanje, kontakti s veterinarima, prijevoz i sigurno kretanje po palubama i dokovima.",
    "safety.marina.title": "Pridržavajte se pravila marine",
    "safety.marina.text":
      "Potvrdite registraciju gostiju, pristup, parkiranje, otpad, buku, sigurnost i hitne postupke s marinom.",
    "safety.redFlags.title": "Prepoznajte crvene zastavice",
    "safety.redFlags.text":
      "Pauzirajte ako vas netko vrši pritisak, izbjegava video, traži neobična plaćanja, uskraćuje dokumentaciju, mijenja ključne činjenice ili pokušava odmah premjestiti razgovor izvan platforme.",
    "safety.reporting.title": "Prijavite incidente",
    "safety.reporting.text":
      "Sačuvajte poruke, fotografije, datume i račune. Prijavite sigurnosne probleme Boatstead podršci i relevantnim osiguravateljima ili tijelima.",
    "safety.emergency.title": "U hitnim slučajevima",
    "safety.emergency.text":
      "Zaštiti život prije svega. Obratite se lokalnoj hitnoj službi ili službi spašavanja na moru, zatim vlasniku, marini i osiguravatelju prema potrebi.",
    "safety.disclaimerTitle": "Važno ograničenje",
    "safety.disclaimerText":
      "Boatstead ne zamjenjuje hitne službe, osiguravatelje, kvalificirane pomorske stručnjake ili profesionalne pomorske savjete.",
    "support.kicker": "Centar za pomoć",
    "support.title": "Kako možemo pomoći?",
    "support.intro":
      "Odaberite kategoriju i pošaljite poruku. Ovaj prototip pohranjuje zahtjeve lokalno i ne šalje e-poštu.",
    "support.categories": "Kategorije podrške",
    "support.topic": "Tema",
