    "support.topic.other": "ostalo",
    "support.formTitle": "Kontaktirajte podršku",
    "support.accountDetails": "Vaš račun",
    "support.accountDetailsHint": "Za vaš zahtjev za podršku koristit ćemo ovo ime i e-poštu.",
    "support.name": "Ime",
    "support.email": "E-mail",
    "support.message": "Poruka",
    "support.requiredError": "Ispunite sva potrebna polja.",
    "support.emailError": "Unesite valjanu adresu e-pošte.",
    "support.submitError": "Vaš zahtjev nije moguće spremiti. Molimo pokušajte ponovo.",
    "support.send": "Pošalji zahtjev",
    "support.sending": "Slanje...",
    "support.success": "Vaš zahtjev za podršku je spremljen.",
    "terms.kicker": "Pravno",
    "terms.title": "Uvjeti usluge",
    "terms.updated": "Zadnje ažuriranje: 24. srpnja 2026",
    "terms.reviewNotice":
      "Obavijest prije lansiranja: kvalificirani pravni savjetnik mora pregledati i prilagoditi ove uvjete prije pokretanja proizvodnje.",
    "terms.eligibility.title": "Podobnost",
    "terms.eligibility.text":
      "Morate biti zakonski sposobni sklapati ugovore i pružati točne podatke da biste koristili Boatstead.",
    "terms.accounts.title": "Računi",
    "terms.accounts.text":
      "Vi ste odgovorni za svoj račun, podatke za prijavu i aktivnost. Odmah nas obavijestite o neovlaštenom pristupu.",
    "terms.platform.title": "Uloga platforme",
    "terms.platform.text":
      "Boatstead samo olakšava upoznavanje vlasnika brodova i čuvara. Svaki dogovor o čuvanju ugovor je između vlasnika i čuvara. Boatstead ne posjeduje plovila, ne zapošljava članove, ne nadgleda čuvanja i ne postaje strana tih dogovora.",
    "terms.listings.title": "Popisi i aplikacije",
    "terms.listings.text":
      "Popisi i prijave moraju biti točni, aktualni i potpuni. Članovi odlučuju hoće li ući u raspored sjedenja.",
    "terms.responsibilities.title": "Odgovornosti korisnika",
    "terms.responsibilities.text":
      "Članovi moraju djelovati zakonito, komunicirati pošteno, slijediti pisana očekivanja i biti oprezni.",
    "terms.verification.title": "Provjera",
    "terms.verification.text":
      "Provjere mogu smanjiti rizik, ali ne jamče identitet, ponašanje, kvalifikacije, sigurnost ili prikladnost.",
    "terms.prohibited.title": "Zabranjeno ponašanje",
    "terms.prohibited.text":
      "Nemojte počiniti prijevaru, uznemiravanje, diskriminaciju, nesigurne radnje, neovlašteni pristup, nezakonite aktivnosti ili zlouporabu platforme.",
    "terms.nonDiscrimination.title": "Nediskriminacija",
    "terms.nonDiscrimination.text":
      "Ne smijete diskriminirati nijednog člana na temelju zaštićenih obilježja, uključujući rasu, boju kože, etničku pripadnost, nacionalno podrijetlo, vjeru, spol, rod, rodni identitet, rodno izražavanje, seksualnu orijentaciju, dob, invaliditet, bračni status ili bilo koji drugi status zaštićen primjenjivim pravom. Diskriminacija u oglasima, prijavama, porukama, odlukama o odabiru ili drugoj uporabi Boatsteada zabranjena je.",
    "terms.payments.title": "Plaćanja i naknade",
    "terms.payments.text":
      "Boatstead trenutno ne naplaćuje noćnu naknadu. Ako se uvedu značajke koje se plaćaju, prvo će se prikazati primjenjivi uvjeti i cijene.",
    "terms.cancellations.title": "Otkazivanja",
    "terms.cancellations.text":
      "Članovi se trebaju složiti s planovima otkazivanja u pisanom obliku i odmah priopćiti promjene kako bi smanjili štetu i troškove.",
    "terms.insurance.title": "Osiguranje",
    "terms.insurance.text":
      "Članovi su odgovorni za potvrdu odgovarajućeg osiguranja. Boatstead ne nudi osiguranje plovila, putovanja ili osiguranje od odgovornosti.",
    "terms.damage.title": "Štete i potraživanja",
    "terms.damage.text":
      "Svaki zahtjev zbog štete, krađe ili sličnog događaja primarno je između vlasnika i čuvara. Odmah dokumentirajte incidente, sačuvajte dokaze i surađujte s drugom stranom, marinama, osiguravateljima i vlastima.",
    "terms.intellectualProperty.title": "Intelektualno vlasništvo",
    "terms.intellectualProperty.text":
      "Boatstead sadržaj i brendiranje su zaštićeni. Zadržavate prava na svoj sadržaj i dajete nam dopuštenje za upravljanje uslugom.",
    "terms.privacy.title": "Privatnost",
    "terms.privacy.text":
      "S osobnim podacima mora se postupati odgovorno. Obavijest o privatnosti proizvodnje opisat će prikupljanje, korištenje, zadržavanje i prava.",
    "terms.termination.title": "Obustava i raskid",
    "terms.termination.text":
      "Možemo ograničiti ili prekinuti pristup kako bismo zaštitili članove, istražili nedoumice, proveli uvjete ili bili u skladu sa zakonom.",
    "terms.disclaimers.title": "Odricanje od odgovornosti",
    "terms.disclaimers.text":
      "Prototip je dostupan kao dostupan bez jamstava neprekinutog rada, prikladnosti, točnosti ili rezultata.",
    "terms.liability.title": "Ograničenje odgovornosti",
    "terms.liability.text":
      "U mjeri dopuštenoj zakonom, Boatstead nije odgovoran za štetu, krađu, gubitak, ozljede, prekid putovanja, potraživanja u vezi s imovinom ni za bilo koji drugi ishod koji proizlazi iz dogovora među članovima. Članovi međusobno postupaju na vlastitu odgovornost.",
    "terms.indemnity.title": "Odšteta",
    "terms.indemnity.text":
      "Gdje je to zakonski dopušteno, suglasni ste pokriti zahtjeve uzrokovane vašim nezakonitim ponašanjem, sadržajem ili kršenjem ovih uvjeta.",
    "terms.disputes.title": "Sporovi i mjerodavno pravo",
    "terms.disputes.text":
      "Uvjeti proizvodnje moraju navesti subjekt tvrtke, jurisdikciju, mjerodavno pravo i postupak spora nakon pravne provjere.",
    "terms.changes.title": "Promjene ovih uvjeta",
    "terms.changes.text":
      "Možemo ažurirati ove uvjete i dostavit ćemo odgovarajuću obavijest prije nego materijalne promjene stupe na snagu.",
    "terms.contact.title": "Kontakt i podrška",
    "terms.contact.text":
      "Za pitanja koristite stranicu za podršku. Nemojte se oslanjati na Boatstead podršku za odgovor u hitnim slučajevima.",
    "nav.admin": "Admin",
