    "safety.kicker": "Güven ve emniyet",
    "safety.title": "Daha güvenli tekne oturuşu hazırlıkla başlar",
    "safety.intro":
      "Her tekneye binmeden önce, sırasında ve sonrasında bu pratik kontrolleri kullanın.",
    "safety.verification.title": "Kimlik ve doğrulama",
    "safety.verification.text":
      "Oturma iznini kabul etmeden önce mevcut kimlik kontrollerini tamamlayın ve adların ve iletişim bilgilerinin eşleştiğini doğrulayın.",
    "safety.profiles.title": "Profilleri ve geçmişi inceleyin",
    "safety.profiles.text":
      "Referansları, incelemeleri ve deneyimleri dikkatlice okuyun. Boşluklar veya tanıdık olmayan sistemler hakkında takip soruları sorun.",
    "safety.video.title": "Videoyla tanışın",
    "safety.video.text":
      "Bir video görüşmesi düzenleyin, gemide kalacak ve uygun olduğunda gemide canlı olarak dolaşacak herkesi dahil edin.",
    "safety.expectations.title": "Beklentilerinizi yazılı hale getirin",
    "safety.expectations.text":
      "Tarihleri, sorumlulukları, erişimi, harcamaları, güncellemeleri, ziyaretçileri ve iptal planlarını yazılı olarak kaydedin.",
    "safety.handover.title": "Tekneye özel bir devir teslim işlemini tamamlayın",
    "safety.handover.text":
      "Örtü sistemleri, deniz muslukları, sintineler, bataryalar, kıyı gücü, motorlar, hava durumu işlemleri, acil durum kontakları ve kapatma prosedürleri.",
    "safety.insurance.title": "Sigortayı kontrol edin",
    "safety.insurance.text":
      "Sahipler ve bakıcılar, geçerli gemi, marina, seyahat, sorumluluk ve kişisel sigortayı bağımsız olarak onaylamalıdır.",
    "safety.pets.title": "Evcil hayvanlar için plan yapın",
    "safety.pets.text":
      "Beslemeyi, ilaçları, egzersizi, veteriner temaslarını, taşımayı ve güverte ve rıhtım çevresinde güvenli hareketi belgeleyin.",
    "safety.marina.title": "Marina kurallarına uyun",
    "safety.marina.text":
      "Marina ile misafir kaydı, erişim, otopark, atık, gürültü, güvenlik ve acil durum prosedürlerini onaylayın.",
    "safety.redFlags.title": "Kırmızı bayrakları tanıyın",
    "safety.redFlags.text":
      "Birisi size baskı yapıyorsa, videodan kaçınıyorsa, alışılmadık ödemeler talep ediyorsa, belgeleri saklıyorsa, önemli gerçekleri değiştiriyorsa veya konuşmayı hemen platform dışına taşımak istiyorsa duraklayın.",
    "safety.reporting.title": "Olayları bildir",
    "safety.reporting.text":
      "Mesajları, fotoğrafları, tarihleri ve makbuzları koruyun. Güvenlik endişelerini Boatstead desteğine ve ilgili sigorta şirketlerine veya yetkililere bildirin.",
    "safety.emergency.title": "Acil bir durumda",
    "safety.emergency.text":
      "Önce yaşamı koruyun. Yerel acil durum veya deniz kurtarma hizmetleriyle, ardından uygun şekilde yat sahibiyle, marinayla ve sigortacıyla iletişime geçin.",
    "safety.disclaimerTitle": "Önemli sınırlama",
    "safety.disclaimerText":
      "Boatstead acil servislerin, sigortacıların, nitelikli denizcilik profesyonellerinin veya profesyonel denizcilik danışmanlığının yerini almaz.",
    "support.kicker": "Yardım merkezi",
