type LocaleExtraKey = keyof (typeof localeExtrasSource)["en-US"];

function mapLocaleValues(
  base: Record<LocaleExtraKey, string>,
  transform: (value: string) => string,
  overrides: Partial<Record<LocaleExtraKey, string>> = {},
): Record<LocaleExtraKey, string> {
  const next = {} as Record<LocaleExtraKey, string>;
  for (const key of Object.keys(base) as LocaleExtraKey[]) {
    next[key] = overrides[key] ?? transform(base[key]);
  }
  return next;
}

/** European Spanish → Latin American Spanish wording. */
function toLatinAmericanSpanish(value: string): string {
  return value
    .replaceAll("Ingrese ", "Ingresa ")
    .replaceAll("Introduzca ", "Ingresa ")
    .replaceAll("Introduce ", "Ingresa ")
    .replaceAll("Estancias", "Estadías")
    .replaceAll("estancias", "estadías")
    .replaceAll("Estancia", "Estadía")
    .replaceAll("estancia", "estadía")
    .replaceAll("ordenador", "computadora")
    .replaceAll("Ordenador", "Computadora")
    .replaceAll("móviles", "celulares")
    .replaceAll("Móviles", "Celulares")
    .replaceAll("móvil", "celular")
    .replaceAll("Móvil", "Celular")
    .replaceAll("aparcamiento", "estacionamiento")
    .replaceAll("Aparcamiento", "Estacionamiento")
    .replaceAll("vosotros", "ustedes")
    .replaceAll("Vosotros", "Ustedes");
}

/** European Portuguese → Brazilian Portuguese wording. */
function toBrazilianPortuguese(value: string): string {
  return value
    .replaceAll("Palavras-passe", "Senhas")
    .replaceAll("palavras-passe", "senhas")
    .replaceAll("Palavra-passe", "Senha")
    .replaceAll("palavra-passe", "senha")
    .replaceAll("Utilizadores", "Usuários")
    .replaceAll("utilizadores", "usuários")
    .replaceAll("Utilizador", "Usuário")
    .replaceAll("utilizador", "usuário")
    .replaceAll("Telemóveis", "Celulares")
    .replaceAll("telemóveis", "celulares")
    .replaceAll("Telemóvel", "Celular")
    .replaceAll("telemóvel", "celular")
    .replaceAll("Equipas", "Equipes")
    .replaceAll("equipas", "equipes")
    .replaceAll("Equipa", "Equipe")
    .replaceAll("equipa", "equipe")
    .replaceAll("Contactos", "Contatos")
    .replaceAll("contactos", "contatos")
    .replaceAll("Contacto", "Contato")
    .replaceAll("contacto", "contato")
    .replaceAll("Ficheiros", "Arquivos")
    .replaceAll("ficheiros", "arquivos")
    .replaceAll("Ficheiro", "Arquivo")
    .replaceAll("ficheiro", "arquivo")
    .replaceAll("Actualizar", "Atualizar")
    .replaceAll("actualizar", "atualizar")
    .replaceAll("Actualiza", "Atualiza")
    .replaceAll("actualiza", "atualiza")
    .replaceAll("Electrónico", "Eletrônico")
    .replaceAll("electrónico", "eletrônico")
    .replaceAll("Eletrónico", "Eletrônico")
    .replaceAll("eletrónico", "eletrônico")
    .replaceAll("Autocarro", "Ônibus")
    .replaceAll("autocarro", "ônibus")
    .replaceAll("Descarregar", "Baixar")
    .replaceAll("descarregar", "baixar")
    .replaceAll("Descarregue", "Baixe")
    .replaceAll("descarregue", "baixe");
}

